class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        s, r = 0, 0
        while s < len(start) and r < len(result):
            if start[s] == result[r]:
                s += 1
                r += 1
            elif start[s] == 'X':
                s += 1
            elif result[r] == 'X':
                r += 1
            elif start[s] == 'L' and result[r] == 'R':
                return False
            elif start[s] == 'R' and result[r] == 'L':
                return False
            else:
                s += 1
                r += 1
        return s == len(start) and r == len(result)
